import{_ as a,C as s,o as r,c as i,j as t,a as n,E as d,ae as l}from"./chunks/framework.D7zHIyZF.js";const w=JSON.parse('{"title":"","description":"","frontmatter":{"layout":"home","hero":{"name":"jai","text":"Go hard on agents, not on your filesystem.","tagline":"Use jai for effortless containment of AI agents on Linux.","actions":[{"theme":"brand","text":"Get Started","link":"/quick-start"},{"theme":"alt","text":"Security Model","link":"/security"}]}},"headers":[],"relativePath":"index.md","filePath":"index.md"}'),c={name:"index.md"},h={class:"home-content"},p={class:"incidents-section"};function u(m,e,f,g,v,y){const o=s("IncidentCarousel");return r(),i("div",null,[t("div",h,[t("section",p,[e[0]||(e[0]=t("h2",{id:"this-is-not-hypothetical",tabindex:"-1"},[n("This is not hypothetical. "),t("a",{class:"header-anchor",href:"#this-is-not-hypothetical","aria-label":'Permalink to "This is not hypothetical."'},"​")],-1)),e[1]||(e[1]=t("p",null,"People are already reporting lost files, emptied working trees, and wiped home directories after giving AI tools ordinary machine access.",-1)),d(o)]),e[2]||(e[2]=l('<section class="reasons-section"><p>There&#39;s a gap between giving an agent your real account and stopping everything to build a container or VM. <strong>jai fills that gap.</strong> One command, no images, no Dockerfiles — just a light-weight boundary for the workflows you&#39;re already running: quick coding help, one-off local tasks, running installer scripts you didn&#39;t write.</p><div class="reason-grid"><div class="reason-card"><h3>Your files, your rules</h3><p>Use AI agents without handing over your whole account. jai gives your working directory full access and keeps the rest of your home behind a copy-on-write overlay — or hidden entirely.</p></div><div class="reason-card"><h3>Stop trusting blindly</h3><p>One-line installer scripts, AI-generated shell commands, unfamiliar CLIs — stop running them against your real home directory. Drop <code>jai</code> in front and the worst case gets a lot smaller.</p></div><div class="reason-card"><h3>Containment shouldn&#39;t be hard</h3><p>No images to build, no Dockerfiles to maintain, no 40-flag bwrap invocations. Just <code>jai your-agent</code>. If containment isn&#39;t easier than YOLO mode, nobody will bother.</p></div></div></section><section class="how-section"><h2 id="how-it-works" tabindex="-1">How it works <a class="header-anchor" href="#how-it-works" aria-label="Permalink to &quot;How it works&quot;">​</a></h2><p>One command. No setup required.</p><div class="steps-grid"><div class="step"><span class="step-num">1</span><p><strong>Prefix your command</strong><br><code>jai codex</code>, <code>jai claude</code>, or just <code>jai</code> for a shell.</p></div><div class="step"><span class="step-num">2</span><p><strong>CWD stays writable</strong><br>Your working directory keeps full read/write access inside the jail.</p></div><div class="step"><span class="step-num">3</span><p><strong>Home is an overlay</strong><br>Changes to your home directory are captured copy-on-write. Originals are untouched.</p></div><div class="step"><span class="step-num">4</span><p><strong>Rest is locked down</strong><br><code>/tmp</code> and <code>/var/tmp</code> are private. All other files are read-only.</p></div></div></section><section class="modes-section"><h2 id="three-modes" tabindex="-1">Three modes <a class="header-anchor" href="#three-modes" aria-label="Permalink to &quot;Three modes&quot;">​</a></h2><p>Pick the level of isolation that fits your workflow.</p><div class="mode-table"><table tabindex="0"><thead><tr><th></th><th>Casual</th><th>Strict</th><th>Bare</th></tr></thead><tbody><tr><td>Home directory</td><td>Copy-on-write overlay</td><td>Empty private home</td><td>Empty private home</td></tr><tr><td>Process runs as</td><td>Your user</td><td>Unprivileged <code>jai</code> user</td><td>Your user</td></tr><tr><td>Confidentiality</td><td>Weak — most files readable</td><td>Strong — separate UID</td><td>Medium — your UID, but home hidden</td></tr><tr><td>Integrity</td><td>Overlay protects originals</td><td>Full isolation</td><td>Full isolation</td></tr><tr><td>NFS home support</td><td>Yes</td><td>No</td><td>Yes</td></tr></tbody></table></div><div class="section-link"><p><a href="/modes.html">Learn more about modes →</a></p></div></section><section class="free-section"><h2 id="free-software-not-a-funnel" tabindex="-1">Free software, not a funnel <a class="header-anchor" href="#free-software-not-a-funnel" aria-label="Permalink to &quot;Free software, not a funnel&quot;">​</a></h2><p>jai is free software, brought to you by the <a href="https://www.scs.stanford.edu/" target="_blank" rel="noreferrer">Stanford Secure Computer Systems</a> research group and the <a href="https://fdc.stanford.edu/" target="_blank" rel="noreferrer">Future of Digital Currency Initiative</a>. The goal is to get people using AI more safely.</p></section><section class="compare-section"><h2 id="versus-the-alternatives" tabindex="-1">Versus the alternatives <a class="header-anchor" href="#versus-the-alternatives" aria-label="Permalink to &quot;Versus the alternatives&quot;">​</a></h2><p>jai is not trying to replace containers. It fills a different niche.</p><div class="compare-grid"><div class="compare-card"><h3>Docker</h3><p>Great for reproducible, image-based environments. Heavier to set up for ad-hoc sandboxing of host tools. No overlay-on-home workflow.</p></div><div class="compare-card"><h3>bubblewrap</h3><p>Powerful namespace sandbox. Requires explicitly assembling the filesystem view — often turns into a long wrapper script, which is the friction jai removes.</p></div><div class="compare-card"><h3>chroot</h3><p>Not a security mechanism. No mount isolation, no PID namespace, no credential separation. Linux documents it as not intended for sandboxing.</p></div></div><div class="section-link"><p><a href="/comparison.html">Full comparison →</a></p></div></section><div class="honest-callout"><h3>jai is not a promise of perfect safety.</h3><p>jai is a casual sandbox — it reduces the blast radius, but does not eliminate all the ways AI agents can harm you or your system. Casual mode does not protect confidentiality. Even strict mode is not equivalent to a hardened container runtime or VM. When you need strong multi-tenant isolation or defense against a determined adversary, use a proper container or virtual machine. <a href="/security.html">Read the full security model →</a></p></div>',6))])])}const k=a(c,[["render",u]]);export{w as __pageData,k as default};
